import{_ as a,c as s,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"階段 1：Bootstrap - 結構化產品想法 | Agent App Factory 教學","description":"學習 Bootstrap 階段如何將模糊的產品想法轉化為清晰、結構化的 input/idea.md 文件。本教學講解 Bootstrap Agent 的職責、superpowers:brainstorm 技能的使用、idea.md 的標準結構和品質檢查清單。","frontmatter":{"title":"階段 1：Bootstrap - 結構化產品想法 | Agent App Factory 教學","sidebarTitle":"結構化產品想法","subtitle":"階段 1：Bootstrap - 結構化產品想法","description":"學習 Bootstrap 階段如何將模糊的產品想法轉化為清晰、結構化的 input/idea.md 文件。本教學講解 Bootstrap Agent 的職責、superpowers:brainstorm 技能的使用、idea.md 的標準結構和品質檢查清單。","tags":["管線","Bootstrap","產品想法"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"zh-tw/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md","filePath":"zh-tw/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"}'),e={name:"zh-tw/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"};function l(r,t,n,p,d,h){return o(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="階段-1-bootstrap-結構化產品想法" tabindex="-1">階段 1：Bootstrap - 結構化產品想法 <a class="header-anchor" href="#階段-1-bootstrap-結構化產品想法" aria-label="Permalink to &quot;階段 1：Bootstrap - 結構化產品想法&quot;">​</a></h1><p>Bootstrap 是 Agent App Factory 管線的第一個階段，負責將你模糊的產品想法整理成清晰的 <code>input/idea.md</code> 文件。這是後續 PRD、UI、Tech 等所有階段的起點，決定了整個專案的方向和品質。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>將模糊的產品想法整理為符合標準模板的 <code>input/idea.md</code> 文件</li><li>理解 Bootstrap Agent 的職責邊界（只收集資訊，不創造需求）</li><li>知道如何使用 superpowers:brainstorm 技能深入挖掘產品想法</li><li>能夠判斷什麼資訊應該包含在 Bootstrap 階段，什麼不該包含</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你可能有一個產品想法，但描述得很模糊：</p><ul><li>&quot;我想做一個健身應用程式&quot;（太泛）</li><li>&quot;做一個像小紅書一樣的應用程式&quot;（沒說差異化）</li><li>&quot;使用者需要一個更好的任務管理工具&quot;（沒說具體問題）</li></ul><p>這種模糊的描述會導致後續階段（PRD、UI、Tech）缺乏明確的輸入，最終生成的應用程式可能完全偏離你的預期。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p>當你準備好啟動管線，並且滿足以下條件時：</p><ol><li><strong>有一個初步的產品想法</strong>（哪怕只是一句話）</li><li><strong>還沒開始寫需求文件</strong>（PRD 在後續階段）</li><li><strong>還沒決定技術堆疊或 UI 風格</strong>（這些在後續階段）</li><li><strong>希望控制產品範圍，避免過度設計</strong>（Bootstrap 階段會明確非目標）</li></ol><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置條件</p><p>在開始 Bootstrap 階段前，請確保：</p><ul><li>✅ 已完成 <a href="./../../start/init-project/">專案初始化</a></li><li>✅ 已了解 <a href="./../../start/pipeline-overview/">7 階段管線概覽</a></li><li>✅ 已安裝並設定好 AI 助手（推薦 Claude Code）</li><li>✅ 已準備好你的產品想法（哪怕是模糊的）</li></ul></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什麼是-bootstrap-階段" tabindex="-1">什麼是 Bootstrap 階段？ <a class="header-anchor" href="#什麼是-bootstrap-階段" aria-label="Permalink to &quot;什麼是 Bootstrap 階段？&quot;">​</a></h3><p><strong>Bootstrap</strong> 是整個管線的起點，它的唯一職責是<strong>將碎片化的產品想法整理為結構化的文件</strong>。</p><div class="info custom-block"><p class="custom-block-title">不是產品經理</p><p>Bootstrap Agent 不是產品經理，它不會替你創造需求或設計功能。它的任務是：</p><ul><li>收集你已經提供的資訊</li><li>梳理並組織這些資訊</li><li>按照標準模板呈現</li></ul><p>它不會決定&quot;應該有什麼功能&quot;，只會幫你把&quot;你想要什麼&quot;說清楚。</p></div><h3 id="為什麼要結構化" tabindex="-1">為什麼要結構化？ <a class="header-anchor" href="#為什麼要結構化" aria-label="Permalink to &quot;為什麼要結構化？&quot;">​</a></h3><p>想像一下，你告訴廚師：&quot;我想吃點好吃的&quot;</p><ul><li>❌ 模糊的描述：廚師只能猜測，可能做出你完全不想吃的菜</li><li>✅ 結構化的描述：&quot;我想要一道辣的、不放香菜的川菜，希望能下飯&quot;</li></ul><p>Bootstrap 階段就是把&quot;我想吃點好吃的&quot;變成&quot;辣的、不放香菜的川菜&quot;。</p><h3 id="輸出文件結構" tabindex="-1">輸出文件結構 <a class="header-anchor" href="#輸出文件結構" aria-label="Permalink to &quot;輸出文件結構&quot;">​</a></h3><p>Bootstrap 階段會生成 <code>input/idea.md</code>，包含以下章節：</p><table tabindex="0"><thead><tr><th>章節</th><th>內容</th><th>範例</th></tr></thead><tbody><tr><td><strong>簡要描述</strong></td><td>1-2 句話概括產品</td><td>&quot;一個行動端記帳應用程式，幫助年輕人快速記錄日常支出&quot;</td></tr><tr><td><strong>問題 (Problem)</strong></td><td>使用者遇到的核心痛點</td><td>&quot;年輕人月底發現超支，但不知道錢花在哪&quot;</td></tr><tr><td><strong>目標使用者 (Target User)</strong></td><td>具體的人群畫像</td><td>&quot;18-30 歲剛工作的年輕人，技術能力中等&quot;</td></tr><tr><td><strong>核心價值 (Core Value)</strong></td><td>為什麼有價值</td><td>&quot;3 秒記帳，比手動查詢節省 80% 時間&quot;</td></tr><tr><td><strong>假設 (Assumptions)</strong></td><td>2-4 條可驗證的假設</td><td>&quot;使用者願意花 2 分鐘學習應用程式，如果能控制預算&quot;</td></tr><tr><td><strong>非目標 (Non‑Goals)</strong></td><td>明確不做什麼</td><td>&quot;不做預算規劃和財務建議&quot;</td></tr></tbody></table><h2 id="跟我操作" tabindex="-1">跟我操作 <a class="header-anchor" href="#跟我操作" aria-label="Permalink to &quot;跟我操作&quot;">​</a></h2><h3 id="第-1-步-準備你的產品想法" tabindex="-1">第 1 步：準備你的產品想法 <a class="header-anchor" href="#第-1-步-準備你的產品想法" aria-label="Permalink to &quot;第 1 步：準備你的產品想法&quot;">​</a></h3><p>在開始管線前，先想清楚你的產品想法。可以是一個完整的描述，也可以只是一個簡單的想法。</p><p><strong>範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想做一個健身應用程式，幫助健身新手記錄訓練，包括運動類型、時長、卡路里，還能查看本週統計。</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">想法可以很粗糙</p><p>哪怕只是一句話也沒關係，Bootstrap Agent 會透過 superpowers:brainstorm 技能幫你補充完整資訊。</p></div><h3 id="第-2-步-啟動管線到-bootstrap-階段" tabindex="-1">第 2 步：啟動管線到 Bootstrap 階段 <a class="header-anchor" href="#第-2-步-啟動管線到-bootstrap-階段" aria-label="Permalink to &quot;第 2 步：啟動管線到 Bootstrap 階段&quot;">​</a></h3><p>在 Factory 專案目錄中執行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 啟動管線（如果還沒啟動）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或直接指定從 bootstrap 開始</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootstrap</span></span></code></pre></div><p>CLI 會顯示目前狀態和可用階段。</p><h3 id="第-3-步-ai-助手讀取-bootstrap-agent-定義" tabindex="-1">第 3 步：AI 助手讀取 Bootstrap Agent 定義 <a class="header-anchor" href="#第-3-步-ai-助手讀取-bootstrap-agent-定義" aria-label="Permalink to &quot;第 3 步：AI 助手讀取 Bootstrap Agent 定義&quot;">​</a></h3><p>AI 助手（如 Claude Code）會自動讀取 <code>agents/bootstrap.agent.md</code>，了解其職責和限制。</p><div class="info custom-block"><p class="custom-block-title">Agent 職責</p><p>Bootstrap Agent 只能：</p><ul><li>讀取使用者在對話中提供的產品想法</li><li>寫入 <code>input/idea.md</code></li></ul><p>它不能：</p><ul><li>讀取其他文件</li><li>寫入其他目錄</li><li>創造新需求</li></ul></div><h3 id="第-4-步-強制使用-superpowers-brainstorm-技能" tabindex="-1">第 4 步：強制使用 superpowers:brainstorm 技能 <a class="header-anchor" href="#第-4-步-強制使用-superpowers-brainstorm-技能" aria-label="Permalink to &quot;第 4 步：強制使用 superpowers:brainstorm 技能&quot;">​</a></h3><p>這是 Bootstrap 階段的關鍵步驟。AI 助手<strong>必須</strong>先呼叫 <code>superpowers:brainstorm</code> 技能，即使你認為資訊已經很完整。</p><p><strong>brainstorm 技能的作用</strong>：</p><ol><li><strong>深入挖掘問題本質</strong>：透過結構化提問發現你描述中的盲點</li><li><strong>明確目標使用者畫像</strong>：幫你想清楚&quot;到底賣給誰&quot;</li><li><strong>驗證核心價值</strong>：透過對比競品找到差異化</li><li><strong>識別隱含假設</strong>：列出那些你預設但未經驗證的假設</li><li><strong>控制產品範圍</strong>：透過非目標明確邊界</li></ol><p><strong>AI 助手會做什麼</strong>：</p><ul><li>呼叫 <code>superpowers:brainstorm</code> 技能</li><li>提供你的原始想法</li><li>透過技能生成的問題向你提問</li><li>收集你的回答並完善想法</li></ul><div class="danger custom-block"><p class="custom-block-title">跳過此步驟會被拒絕</p><p>Sisyphus 排程器會驗證是否使用了 brainstorm 技能。如果沒有，Bootstrap Agent 生成的產物會被拒絕，需要重新執行。</p></div><h3 id="第-5-步-確認-idea-md-內容" tabindex="-1">第 5 步：確認 idea.md 內容 <a class="header-anchor" href="#第-5-步-確認-idea-md-內容" aria-label="Permalink to &quot;第 5 步：確認 idea.md 內容&quot;">​</a></h3><p>Bootstrap Agent 完成後，會生成 <code>input/idea.md</code>。你需要仔細檢查：</p><p><strong>檢查點 ✅</strong>：</p><ol><li><p><strong>簡要描述</strong>是否清晰？</p><ul><li>✅ 包含：做什麼 + 為誰做 + 解決什麼問題</li><li>❌ 太泛：&quot;一個提高效率的工具&quot;</li></ul></li><li><p><strong>問題描述</strong>是否具體？</p><ul><li>✅ 包含：場景 + 困難 + 負面結果</li><li>❌ 空泛：&quot;使用者體驗不好&quot;</li></ul></li><li><p><strong>目標使用者</strong>是否明確？</p><ul><li>✅ 有具體畫像（年齡/職業/技術能力）</li><li>❌ 模糊：&quot;所有人&quot;</li></ul></li><li><p><strong>核心價值</strong>是否可量化？</p><ul><li>✅ 有具體收益（節省 80% 時間）</li><li>❌ 空泛：&quot;提升效率&quot;</li></ul></li><li><p><strong>假設</strong>是否可驗證？</p><ul><li>✅ 可透過使用者調研驗證</li><li>❌ 主觀判斷：&quot;使用者會喜歡&quot;</li></ul></li><li><p><strong>非目標</strong>是否充分？</p><ul><li>✅ 至少列出 3 項不做的功能</li><li>❌ 缺失或太少</li></ul></li></ol><h3 id="第-6-步-選擇繼續、重試或暫停" tabindex="-1">第 6 步：選擇繼續、重試或暫停 <a class="header-anchor" href="#第-6-步-選擇繼續、重試或暫停" aria-label="Permalink to &quot;第 6 步：選擇繼續、重試或暫停&quot;">​</a></h3><p>確認無誤後，CLI 會顯示選項：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">請選擇操作：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1] 繼續（進入 PRD 階段）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[2] 重試（重新生成 idea.md）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[3] 暫停（稍後繼續）</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">建議先在程式碼編輯器中查看</p><p>在 AI 助手中確認前，先用程式碼編輯器開啟 <code>input/idea.md</code>，逐字檢查。一旦進入 PRD 階段，修改成本會更高。</p></div><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="坑-1-想法描述太模糊" tabindex="-1">坑 1：想法描述太模糊 <a class="header-anchor" href="#坑-1-想法描述太模糊" aria-label="Permalink to &quot;坑 1：想法描述太模糊&quot;">​</a></h3><p><strong>錯誤範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想做一個健身應用程式</span></span></code></pre></div><p><strong>後果</strong>：Bootstrap Agent 會透過 brainstorm 技能問很多問題，補充資訊。</p><p><strong>建議</strong>：一開始就描述清楚：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想做一個行動端健身應用程式，幫助健身新手記錄訓練，包括運動類型、時長、卡路里，還能查看本週統計。</span></span></code></pre></div><h3 id="坑-2-包含技術實作細節" tabindex="-1">坑 2：包含技術實作細節 <a class="header-anchor" href="#坑-2-包含技術實作細節" aria-label="Permalink to &quot;坑 2：包含技術實作細節&quot;">​</a></h3><p><strong>錯誤範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我希望使用 React Native 建構，後端用 Express，資料庫是 Prisma...</span></span></code></pre></div><p><strong>後果</strong>：Bootstrap Agent 會拒絕這些內容（它只收集產品想法，技術堆疊在 Tech 階段決定）。</p><p><strong>建議</strong>：只說&quot;做什麼&quot;，不說&quot;怎麼做&quot;。</p><h3 id="坑-3-目標使用者描述太泛" tabindex="-1">坑 3：目標使用者描述太泛 <a class="header-anchor" href="#坑-3-目標使用者描述太泛" aria-label="Permalink to &quot;坑 3：目標使用者描述太泛&quot;">​</a></h3><p><strong>錯誤範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>所有需要健身的人</span></span></code></pre></div><p><strong>後果</strong>：後續階段無法明確設計方向。</p><p><strong>建議</strong>：明確畫像：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>18-30 歲健身新手，剛開始系統訓練，技術能力中等，希望簡單記錄和查看統計。</span></span></code></pre></div><h3 id="坑-4-非目標缺失或太少" tabindex="-1">坑 4：非目標缺失或太少 <a class="header-anchor" href="#坑-4-非目標缺失或太少" aria-label="Permalink to &quot;坑 4：非目標缺失或太少&quot;">​</a></h3><p><strong>錯誤範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>非目標：無</span></span></code></pre></div><p><strong>後果</strong>：後續 PRD 和 Code 階段可能過度設計，增加技術複雜度。</p><p><strong>建議</strong>：至少列出 3 項：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>非目標：</span></span>
<span class="line"><span>- 團隊協作和社交功能（MVP 聚焦個人）</span></span>
<span class="line"><span>- 複雜的資料分析和報表</span></span>
<span class="line"><span>- 與第三方健身裝置整合</span></span></code></pre></div><h3 id="坑-5-假設不可驗證" tabindex="-1">坑 5：假設不可驗證 <a class="header-anchor" href="#坑-5-假設不可驗證" aria-label="Permalink to &quot;坑 5：假設不可驗證&quot;">​</a></h3><p><strong>錯誤範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>假設：使用者會喜歡我們的設計</span></span></code></pre></div><p><strong>後果</strong>：無法透過使用者調研驗證，MVP 可能失敗。</p><p><strong>建議</strong>：寫可驗證的假設：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>假設：使用者願意花 5 分鐘學習應用程式，如果能幫助系統記錄訓練。</span></span></code></pre></div><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>Bootstrap 階段的核心是<strong>結構化</strong>：</p><ol><li><strong>輸入</strong>：你模糊的產品想法</li><li><strong>過程</strong>：AI 助手透過 superpowers:brainstorm 技能深入挖掘</li><li><strong>輸出</strong>：符合標準模板的 <code>input/idea.md</code></li><li><strong>驗證</strong>：檢查描述是否具體、使用者是否明確、價值是否可量化</li></ol><div class="tip custom-block"><p class="custom-block-title">關鍵原則</p><ul><li>❌ 不做什麼：不創造需求、不設計功能、不決定技術堆疊</li><li>✅ 只做什麼：收集資訊、梳理組織、按模板呈現</li></ul></div><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../stage-prd/">階段 2：PRD - 生成產品需求文件</a></strong>。</p><p>你會學到：</p><ul><li>如何將 idea.md 轉化為 MVP 級 PRD</li><li>PRD 包含哪些內容（使用者故事、功能列表、非功能需求）</li><li>如何明確 MVP 範圍和優先級</li><li>為什麼 PRD 不能包含技術細節</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路徑</th><th>行號</th></tr></thead><tbody><tr><td>Bootstrap Agent 定義</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/bootstrap.agent.md" target="_blank" rel="noreferrer"><code>agents/bootstrap.agent.md</code></a></td><td>1-93</td></tr><tr><td>Bootstrap Skill</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/skills/bootstrap/skill.md" target="_blank" rel="noreferrer"><code>skills/bootstrap/skill.md</code></a></td><td>1-433</td></tr><tr><td>管線定義（Bootstrap 階段）</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>8-18</td></tr><tr><td>排程器定義</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-100+</td></tr></tbody></table><p><strong>關鍵限制</strong>：</p><ul><li><strong>強制使用 brainstorm 技能</strong>：bootstrap.agent.md:70-71</li><li><strong>禁止技術細節</strong>：bootstrap.agent.md:47</li><li><strong>禁止合併多個想法</strong>：bootstrap.agent.md:48</li><li><strong>輸出文件必須儲存到 input/idea.md</strong>：bootstrap.agent.md:50</li></ul><p><strong>退出條件</strong>（pipeline.yaml:15-18）：</p><ul><li>idea.md 存在</li><li>idea.md 描述了一個連貫的產品想法</li><li>Agent 已使用 <code>superpowers:brainstorm</code> 技能進行深入挖掘</li></ul><p><strong>Skill 內容框架</strong>：</p><ul><li><strong>思維框架</strong>：提取 vs 創造、問題優先、具體化、假設驗證</li><li><strong>提問模板</strong>：關於問題、目標使用者、核心價值、MVP 假設、非目標</li><li><strong>資訊提取技巧</strong>：從功能反推問題、從抱怨提取需求、識別隱含假設</li><li><strong>品質檢查清單</strong>：完整性、具體性、一致性、禁止項</li><li><strong>決策原則</strong>：優先提問、問題導向、具體優於抽象、可驗證性、範圍控制</li><li><strong>常見場景處理</strong>：使用者只提供一句話、描述很多功能、描述競品、想法矛盾</li><li><strong>範例對比</strong>：不好的 idea.md vs 好的 idea.md</li></ul></details>`,91)])])}const u=a(e,[["render",l]]);export{g as __pageData,u as default};
